-- Drop existing tables if they exist
IF OBJECT_ID('TB_MapExits', 'U') IS NOT NULL DROP TABLE TB_MapExits;
IF OBJECT_ID('TB_MapEntries', 'U') IS NOT NULL DROP TABLE TB_MapEntries;
