-- ==============================================
-- Table: TB_MapExits
-- Map exit portals (teleport to other maps)
-- ==============================================
CREATE TABLE TB_MapExits (
    Id INT IDENTITY(1,1) PRIMARY KEY,
    FromMapId VARCHAR(20) NOT NULL,
    ExitId VARCHAR(20) NOT NULL,
    ToMapId VARCHAR(20) NOT NULL,
    ToEntryId VARCHAR(20) NOT NULL,
    RectX INT NOT NULL DEFAULT 0,
    RectY INT NOT NULL DEFAULT 0,
    RectW INT NOT NULL DEFAULT 0,
    RectH INT NOT NULL DEFAULT 0,
    ExitName NVARCHAR(100) NULL
);
GO

-- ==============================================
-- Table: TB_MapEntries
-- Map entry points (spawn positions)
-- ==============================================
CREATE TABLE TB_MapEntries (
    Id INT IDENTITY(1,1) PRIMARY KEY,
    MapId VARCHAR(20) NOT NULL,
    EntryId VARCHAR(20) NOT NULL,
    PosX INT NOT NULL DEFAULT 0,
    PosY INT NOT NULL DEFAULT 0,
    RectX INT NOT NULL DEFAULT 0,
    RectY INT NOT NULL DEFAULT 0,
    RectW INT NOT NULL DEFAULT 0,
    RectH INT NOT NULL DEFAULT 0,
    EntryName NVARCHAR(100) NULL
);
GO

-- Indexes for fast lookup
CREATE INDEX IX_MapExits_FromMapId_ExitId ON TB_MapExits(FromMapId, ExitId);
CREATE INDEX IX_MapEntries_MapId_EntryId ON TB_MapEntries(MapId, EntryId);
GO

